package main

import (
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"time"
)

const (
	maxFileSize = 10 << 20 // 10MB
	publicDir   = "./public"
	uploadDir   = "./uploads"
)

var allowedExtensions = map[string]bool{
	".jpg":  true, ".jpeg": true, ".png": true, ".gif": true, ".bmp": true,
	".pdf":  true, ".doc": true, ".docx": true, ".txt": true, ".rtf": true,
	".xls":  true, ".xlsx": true, ".ppt": true, ".pptx": true,
	".zip":  true, ".rar": true, ".7z": true, ".tar": true, ".gz": true,
}

func init() {
	if err := os.MkdirAll(publicDir, 0755); err != nil {
		panic(err)
	}
	if err := os.MkdirAll(uploadDir, 0755); err != nil {
		panic(err)
	}
}

func uploadHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	r.ParseMultipartForm(maxFileSize)

	file, handler, err := r.FormFile("file")
	if err != nil {
		http.Error(w, "Error retrieving file", http.StatusBadRequest)
		return
	}
	defer file.Close()

	if handler.Size > maxFileSize {
		http.Error(w, "File too large", http.StatusBadRequest)
		return
	}

	ext := strings.ToLower(filepath.Ext(handler.Filename))
	if !allowedExtensions[ext] {
		http.Error(w, "File type not allowed", http.StatusBadRequest)
		return
	}

	// Generate unique filename to prevent overwrites
	filename := fmt.Sprintf("%d_%s%s", time.Now().Unix(), randomString(10), ext)
	filePath := filepath.Join(publicDir, filename)

	// Create the file in the public directory
	dst, err := os.Create(filePath)
	if err != nil {
		http.Error(w, "Error creating file", http.StatusInternalServerError)
		return
	}
	defer dst.Close()

	// Copy the uploaded file to the destination
	_, err = io.Copy(dst, file)
	if err != nil {
		http.Error(w, "Error saving file", http.StatusInternalServerError)
		return
	}

	// Return the file path
	w.Header().Set("Content-Type", "application/json")
	fmt.Fprintf(w, `{"path": "/%s"}`, filename)
}

func randomString(n int) string {
	letters := "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	b := make([]byte, n)
	for i := range b {
		b[i] = letters[time.Now().UnixNano()%int64(len(letters))]
	}
	return string(b)
}

func main() {
	http.HandleFunc("/upload", uploadHandler)
	http.ListenAndServe(":8080", nil)
}